CREATE DATABASE IsraelMotors;

#GO

USE IsraelMotors; 

CREATE TABLE Customer (
	CustomerNum INT PRIMARY KEY,
	CustomerName VARCHAR(50),
	CustomerAddress VARCHAR(100),
	CustomerPhone VARCHAR(10)
);

CREATE TABLE Car (
	CarNum INT PRIMARY KEY,
	ManufacturerName VARCHAR(30),
	CarYear SMALLINT,
	CarColor VARCHAR(20)
);

CREATE TABLE CarForSale (
	CarNum INT PRIMARY KEY,
	CarSellingPrice INT,
	FOREIGN KEY (CarNum)
		REFERENCES Car(CarNUm)
);

CREATE TABLE CarForRent (
	CarNum INT PRIMARY KEY,
	CarDayPrice SMALLINT,
	CarKM INT,
	FOREIGN KEY (CarNum)
		REFERENCES Car(CarNUm)
);

CREATE TABLE Rents (
	CustomerNum INT,
	RentedCarNum INT,
	RentDays INT,
	PRIMARY KEY (CustomerNum, RentedCarNum),
	FOREIGN KEY (CustomerNum)
		REFERENCES Customer(CustomerNum),
	FOREIGN KEY (RentedCarNum)
		REFERENCES CarForRent (CarNum)
);

CREATE TABLE Buys (
	SoldCarNum INT PRIMARY KEY,
	CustomerNum INT,
	FOREIGN KEY (CustomerNum)
		REFERENCES Customer(CustomerNum),
	FOREIGN KEY (SoldCarNum)
		REFERENCES CarForSale (CarNum)
);

CREATE TABLE Garage (
	GarageNum INT PRIMARY KEY,
	GarageName VARCHAR(50),
	GarageCity VARCHAR(50)
);

CREATE TABLE GarageWorker (
	WorkerNum INT PRIMARY KEY,
	WorkerName VARCHAR(50),
	WorkerSalary SMALLINT,
	GarageNum INT NOT NULL,
	FOREIGN KEY (GarageNum)
		REFERENCES Garage (GarageNum)
);

CREATE TABLE CarService (
	SoldCarNum INT,
	CarTreatmentNum SMALLINT,
	ServiceDate DATE,
	ServiceCost INT,
	WorkerNum INT NOT NULL,
	PRIMARY KEY (SoldCarNum, CarTreatmentNum),
	FOREIGN KEY (SoldCarNum)
		REFERENCES Buys (SoldCarNum),
	FOREIGN KEY (WorkerNum)
		REFERENCES GarageWorker (WorkerNum)
);


